arguments.new_str:
/**
 * Re-order candidates for review diversity: models from a different broad
 * family (claude vs gpt) than lastImplModel float to the front.
 *
 * Uses getModelFamily (broad family) rather than isSameModelFamily (sub-family)
 * so that, e.g., claude-opus-4.5 is deprioritised behind all gpt models when
 * the last implementation used claude-sonnet-4.6 — both are Claude models and
 * should not be preferred over a GPT reviewer for diversity purposes.
 *
 * Accepts lastImplModel as an explicit parameter (rather than reading module
 * state) so the function stays pure and testable.
 */
export function orderCandidates(candidates, route, lastImplModel = null) {
  if (route.kind !== "review" || !lastImplModel) {
    return candidates;
  }
  const implFamily = getModelFamily(lastImplModel);
  return [...candidates].sort((left, right) => {
    const score = (id) => {
      if (id === lastImplModel) return 2;
      // Penalise any model from the same broad family (claude or gpt), not just
      // the same sub-family. This ensures all same-provider models are tried only
      // after distinct-provider models have been exhausted.
      if (implFamily !== null && getModelFamily(id) === implFamily) return 1;
      return 0;
    };
    return score(left.id) - score(right.id); // lower score → earlier in list
  });
}

