  textSnippets.push(...leaves.map((leaf) => ({ line: line.index, ...leaf })));
  usageCandidates.push(...extractUsageCandidates(line.value).map((candidate) => ({ line: line.index, ...candidate })));

  // Capture event timestamps for rough session-duration estimation.
  const ts = line.value.timestamp ?? null;
  if (ts) {
    if (!firstEventTimestamp) firstEventTimestamp = ts;
    lastEventTimestamp = ts;
  }

  // Count tool invocations from execution-start events.
  if (line.value.type === 'tool.execution_start') {
    const toolName = line.value.data?.toolName ?? line.value.data?.tool?.name ?? 'unknown';
    toolCallCounts[toolName] = (toolCallCounts[toolName] ?? 0) + 1;
