// SOURCE-OF-TRUTH CONSISTENCY: routing-matrix.md mentions every MODEL_CANDIDATES entry
//
// This test ensures routing-matrix.md never silently drifts from policy.mjs.
// Whenever a model is added to MODEL_CANDIDATES it must also appear in the matrix.
// ---------------------------------------------------------------------------
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { join, dirname } from "node:path";

const __dirname = dirname(fileURLToPath(import.meta.url));

describe("routing-matrix.md coverage", () => {
  const matrixPath = join(__dirname, "../.github/skills/model-router.eval-disabled/references/routing-matrix.md");
  const matrixText = readFileSync(matrixPath, "utf8");

  const allModels = [
    ...MODEL_CANDIDATES.economy,
    ...MODEL_CANDIDATES.builder,
    ...MODEL_CANDIDATES.reasoning,
  ];

  for (const { id } of allModels) {
    it(`mentions model ${id}`, () => {
      assert.ok(
        matrixText.includes(`\`${id}\``),
        `routing-matrix.md is missing model ${id} — update the matrix when you add models to policy.mjs`
      );
    });
  }
});

// ---------------------------------------------------------------------------
// SOURCE-OF-TRUTH CONSISTENCY: eval/config/models.json matches MODEL_CANDIDATES
//
// models.json is used by the eval harness for tier/family lookups and relative
// cost calculations. This test ensures it never drifts from policy.mjs.
// ---------------------------------------------------------------------------
describe("eval/config/models.json consistency", () => {
  const modelsJsonPath = join(__dirname, "config/models.json");
  const modelsConfig = JSON.parse(readFileSync(modelsJsonPath, "utf8"));
  const jsonModels = modelsConfig.models;

  const TIER_ALIAS = { economy: "economy", builder: "builder", reasoning: "reasoning" };

  it("models.json has a 'models' object", () => {
    assert.ok(typeof jsonModels === "object" && jsonModels !== null, "expected models.json to have a 'models' object");
  });

  for (const [tier, entries] of Object.entries(MODEL_CANDIDATES)) {
    for (const { id } of entries) {
      it(`models.json includes ${id} (tier: ${tier})`, () => {
        assert.ok(
          id in jsonModels,
          `models.json is missing ${id} — add it under "models" when adding to policy.mjs`
        );
        const entry = jsonModels[id];
        assert.equal(
          entry.tier,
          TIER_ALIAS[tier],
          `models.json tier for ${id} is "${entry.tier}" but policy.mjs puts it in "${tier}"`
        );
      });
    }
  }

  it("models.json contains no model absent from MODEL_CANDIDATES", () => {
    const allPolicyIds = new Set([
      ...MODEL_CANDIDATES.economy.map((m) => m.id),
      ...MODEL_CANDIDATES.builder.map((m) => m.id),
      ...MODEL_CANDIDATES.reasoning.map((m) => m.id),
    ]);
    for (const id of Object.keys(jsonModels)) {
      assert.ok(
        allPolicyIds.has(id),
        `models.json has "${id}" which is not in MODEL_CANDIDATES — remove it or add it to policy.mjs`
      );
    }
  });
});

